and delete the file","editTooltip":"Fork this repository and edit the file","ghDesktopPath":"https://desktop.github.com","isGitLfs":false,"onBranch":true,"shortPath":"6e85f81","siteNavLoginPath":"/login?return_to=https%3A%2F%2Fgithub.com%2FPHPMailer%2FPHPMailer%2Fblob%2Fmaster%2Fsrc%2FPOP3.php","isCSV":false,"isRichtext":false,"lineInfo":{"truncatedLoc":"470","truncatedSloc":"418"},"mode":"file"},"image":false,"isCodeownersFile":null,"isPlain":false,"isValidLegacyIssueTemplate":false,"isIssueTemplate":false,"isDiscussionTemplate":false,"language":"PHP","languageID":272,"large":false,"planSupportInfo":{"repoIsFork":null,"repoOwnedByCurrentUser":null,"requestFullPath":"/PHPMailer/PHPMailer/blob/master/src/POP3.php","showFreeOrgGatedFeatureMessage":null,"showPlanSupportBanner":null,"upgradeDataAttributes":null,"upgradePath":null},"publishBannersInfo":{"dismissActionNoticePath":"/settings/dismiss-notice/publish_action_from_dockerfile","releasePath":"/PHPMailer/PHPMailer/releases/new?marketplace=true","showPublishActionBanner":false},"rawBlobUrl":"https://github.com/PHPMailer/PHPMailer/raw/refs/heads/master/src/POP3.php","renderImageOrRaw":false,"shortPath":null,"symbolsEnabled":true,"tabSize":4,"topBannersInfo":{"overridingGlobalFundingFile":false,"globalPreferredFundingPath":null,"showInvalidCitationWarning":false,"citationHelpUrl":"https://docs.github.com/github/creating-cloning-and-archiving-repositories/creating-a-repository-on-github/about-citation-files","actionsOnboardingTip":null},"truncated":false,"viewable":true,"workflowRedirectUrl":null},"copilotInfo":null,"copilotAccessAllowed":true,"copilotSpacesEnabled":true,"modelsAccessAllowed":false,"modelsRepoIntegrationEnabled":false,"isMarketplaceEnabled":true},"codeViewBlobLayoutRoute.StyledBlob":{"rawLines":["\u003c?php","","/**"," * PHPMailer POP-Before-SMTP Authentication Class."," * PHP Version 5.5."," *"," * @see https://github.com/PHPMailer/PHPMailer/ The PHPMailer GitHub project"," *"," * @author    Marcus Bointon (Synchro/coolbru) \u003cphpmailer@synchromedia.co.uk\u003e"," * @author    Jim Jagielski (jimjag) \u003cjimjag@gmail.com\u003e"," * @author    Andy Prevost (codeworxtech) \u003ccodeworxtech@users.sourceforge.net\u003e"," * @author    Brent R. Matzelle (original founder)"," * @copyright 2012 - 2020 Marcus Bointon"," * @copyright 2010 - 2012 Jim Jagielski"," * @copyright 2004 - 2009 Andy Prevost"," * @license   https://www.gnu.org/licenses/old-licenses/lgpl-2.1.html GNU Lesser General Public License"," * @note      This program is distributed in the hope that it will be useful - WITHOUT"," * ANY WARRANTY; without even the implied warranty of MERCHANTABILITY or"," * FITNESS FOR A PARTICULAR PURPOSE."," */","","namespace PHPMailer\\PHPMailer;","","/**"," * PHPMailer POP-Before-SMTP Authentication Class."," * Specifically for PHPMailer to use for RFC1939 POP-before-SMTP authentication."," * 1) This class does not support APOP authentication."," * 2) Opening and closing lots of POP3 connections can be quite slow. If you need"," *   to send a batch of emails then just perform the authentication once at the start,"," *   and then loop through your mail sending script. Providing this process doesn't"," *   take longer than the verification period lasts on your POP3 server, you should be fine."," * 3) This is really ancient technology; you should only need to use it to talk to very old systems."," * 4) This POP3 class is deliberately lightweight and incomplete, implementing just"," *   enough to do authentication."," *   If you want a more complete class there are other POP3 classes for PHP available."," *"," * @author Richard Davey (original author) \u003crich@corephp.co.uk\u003e"," * @author Marcus Bointon (Synchro/coolbru) \u003cphpmailer@synchromedia.co.uk\u003e"," * @author Jim Jagielski (jimjag) \u003cjimjag@gmail.com\u003e"," * @author Andy Prevost (codeworxtech) \u003ccodeworxtech@users.sourceforge.net\u003e"," */","class POP3","{","    /**","     * The POP3 PHPMailer Version number.","     *","     * @var string","     * @deprecated This constant will be removed in PHPMailer 8.0. Use `PHPMailer::VERSION` instead.","     */","    const VERSION = '7.0.2';","","    /**","     * Default POP3 port number.","     *","     * @var int","     */","    const DEFAULT_PORT = 110;","","    /**","     * Default timeout in seconds.","     *","     * @var int","     */","    const DEFAULT_TIMEOUT = 30;","","    /**","     * POP3 class debug output mode.","     * Debug output level.","     * Options:","     * @see POP3::DEBUG_OFF: No output","     * @see POP3::DEBUG_SERVER: Server messages, connection/server errors","     * @see POP3::DEBUG_CLIENT: Client and Server messages, connection/server errors","     *","     * @var int","     */","    public $do_debug = self::DEBUG_OFF;","","    /**","     * POP3 mail server hostname.","     *","     * @var string","     */","    public $host;","","    /**","     * POP3 port number.","     *","     * @var int","     */","    public $port;","","    /**","     * POP3 Timeout Value in seconds.","     *","     * @var int","     */","    public $tval;","","    /**","     * POP3 username.","     *","     * @var string","     */","    public $username;","","    /**","     * POP3 password.","     *","     * @var string","     */","    public $password;","","    /**","     * Resource handle for the POP3 connection socket.","     *","     * @var resource","     */","    protected $pop_conn;","","    /**","     * Are we connected?","     *","     * @var bool","     */","    protected $connected = false;","","    /**","     * Error container.","     *","     * @var array","     */","    protected $errors = [];","","    /**","     * Line break constant.","     */","    const LE = \"\\r\\n\";","","    /**","     * Debug level for no output.","     *","     * @var int","     */","    const DEBUG_OFF = 0;","","    /**","     * Debug level to show server -\u003e client messages","     * also shows clients connection errors or errors from server","     *","     * @var int","     */","    const DEBUG_SERVER = 1;","","    /**","     * Debug level to show client -\u003e server and server -\u003e client messages.","     *","     * @var int","     */","    const DEBUG_CLIENT = 2;","","    /**","     * Simple static wrapper for all-in-one POP before SMTP.","     *","     * @param string   $host        The hostname to connect to","     * @param int|bool $port        The port number to connect to","     * @param int|bool $timeout     The timeout value","     * @param string   $username","     * @param string   $password","     * @param int      $debug_level","     *","     * @return bool","     */","    public static function popBeforeSmtp(","        $host,","        $port = false,","        $timeout = false,","        $username = '',","        $password = '',","        $debug_level = 0","    ) {","        $pop = new self();","","        return $pop-\u003eauthorise($host, $port, $timeout, $username, $password, $debug_level);","    }","","    /**","     * Authenticate with a POP3 server.","     * A connect, login, disconnect sequence","     * appropriate for POP-before SMTP authorisation.","     *","     * @param string   $host        The hostname to connect to","     * @param int|bool $port        The port number to connect to","     * @param int|bool $timeout     The timeout value","     * @param string   $username","     * @param string   $password","     * @param int      $debug_level","     *","     * @return bool","     */","    public function authorise($host, $port = false, $timeout = false, $username = '', $password = '', $debug_level = 0)","    {","        $this-\u003ehost = $host;","        //If no port value provided, use default","        if (false === $port) {","            $this-\u003eport = static::DEFAULT_PORT;","        } else {","            $this-\u003eport = (int) $port;","        }","        //If no timeout value provided, use default","        if (false === $timeout) {","            $this-\u003etval = static::DEFAULT_TIMEOUT;","        } else {","            $this-\u003etval = (int) $timeout;","        }","        $this-\u003edo_debug = $debug_level;","        $this-\u003eusername = $username;","        $this-\u003epassword = $password;","        //Reset the error log","        $this-\u003eerrors = [];","        //Connect","        $result = $this-\u003econnect($this-\u003ehost, $this-\u003eport, $this-\u003etval);","        if ($result) {","            $login_result = $this-\u003elogin($this-\u003eusername, $this-\u003epassword);","            if ($login_result) {","                $this-\u003edisconnect();","","                return true;","            }","        }","        //We need to disconnect regardless of whether the login succeeded","        $this-\u003edisconnect();","","        return false;","    }","","    /**","     * Connect to a POP3 server.","     *","     * @param string   $host","     * @param int|bool $port","     * @param int      $tval","     *","     * @return bool","     */","    public function connect($host, $port = false, $tval = 30)","    {","        //Are we already connected?","        if ($this-\u003econnected) {","            return true;","        }","","        //On Windows this will raise a PHP Warning error if the hostname doesn't exist.","        //Rather than suppress it with @fsockopen, capture it cleanly instead","        set_error_handler(function () {","            call_user_func_array([$this, 'catchWarning'], func_get_args());","        });","","        if (false === $port) {","            $port = static::DEFAULT_PORT;","        }","","        //Connect to the POP3 server","        $errno = 0;","        $errstr = '';","        $this-\u003epop_conn = fsockopen(","            $host, //POP3 Host","            $port, //Port #","            $errno, //Error Number","            $errstr, //Error Message","            $tval","        ); //Timeout (seconds)","        //Restore the error handler","        restore_error_handler();","","        //Did we connect?","        if (false === $this-\u003epop_conn) {","            //It would appear not...","            $this-\u003esetError(","                \"Failed to connect to server $host on port $port. errno: $errno; errstr: $errstr\"","            );","","            return false;","        }","","        //Increase the stream time-out","        stream_set_timeout($this-\u003epop_conn, $tval, 0);","","        //Get the POP3 server response","        $pop3_response = $this-\u003egetResponse();","        //Check for the +OK","        if ($this-\u003echeckResponse($pop3_response)) {","            //The connection is established and the POP3 server is talking","            $this-\u003econnected = true;","","            return true;","        }","","        return false;","    }","","    /**","     * Log in to the POP3 server.","     * Does not support APOP (RFC 2828, 4949).","     *","     * @param string $username","     * @param string $password","     *","     * @return bool","     */","    public function login($username = '', $password = '')","    {","        if (!$this-\u003econnected) {","            $this-\u003esetError('Not connected to POP3 server');","            return false;","        }","        if (empty($username)) {","            $username = $this-\u003eusername;","        }","        if (empty($password)) {","            $password = $this-\u003epassword;","        }","","        //Send the Username","        $this-\u003esendString(\"USER $username\" . static::LE);","        $pop3_response = $this-\u003egetResponse();","        if ($this-\u003echeckResponse($pop3_response)) {","            //Send the Password","            $this-\u003esendString(\"PASS $password\" . static::LE);","            $pop3_response = $this-\u003egetResponse();","            if ($this-\u003echeckResponse($pop3_response)) {","                return true;","            }","        }","","        return false;","    }","","    /**","     * Disconnect from the POP3 server.","     */","    public function disconnect()","    {","        // If could not connect at all, no need to disconnect","        if ($this-\u003epop_conn === false) {","            return;","        }","","        $this-\u003esendString('QUIT' . static::LE);","","        // RFC 1939 shows POP3 server sending a +OK response to the QUIT command.","        // Try to get it.  Ignore any failures here.","        try {","            $this-\u003egetResponse();","        } catch (Exception $e) {","            //Do nothing","        }","","        //The QUIT command may cause the daemon to exit, which will kill our connection","        //So ignore errors here","        try {","            @fclose($this-\u003epop_conn);","        } catch (Exception $e) {","            //Do nothing","        }","","        // Clean up attributes.","        $this-\u003econnected = false;","        $this-\u003epop_conn  = false;","    }","","    /**","     * Get a response from the POP3 server.","     *","     * @param int $size The maximum number of bytes to retrieve","     *","     * @return string","     */","    protected function getResponse($size = 128)","    {","        $response = fgets($this-\u003epop_conn, $size);","        if ($this-\u003edo_debug \u003e= self::DEBUG_SERVER) {","            echo 'Server -\u003e Client: ', $response;","        }","","        return $response;","    }","","    /**","     * Send raw data to the POP3 server.","     *","     * @param string $string","     *","     * @return int","     */","    protected function sendString($string)","    {","        if ($this-\u003epop_conn) {","            if ($this-\u003edo_debug \u003e= self::DEBUG_CLIENT) { //Show client messages when debug \u003e= 2","                echo 'Client -\u003e Server: ', $string;","            }","","            return fwrite($this-\u003epop_conn, $string, strlen($string));","        }","","        return 0;","    }","","    /**","     * Checks the POP3 server response.","     * Looks for +OK or -ERR.","     *","     * @param string $string","     *","     * @return bool","     */","    protected function checkResponse($string)","    {","        if (strpos($string, '+OK') !== 0) {","            $this-\u003esetError(\"Server reported an error: $string\");","","            return false;","        }","","        return true;","    }","","    /**","     * Add an error to the internal error store.","     * Also display debug output if it's enabled.","     *","     * @param string $error","     */","    protected function setError($error)","    {","        $this-\u003eerrors[] = $error;","        if ($this-\u003edo_debug \u003e= self::DEBUG_SERVER) {","            echo '\u003cpre\u003e';","            foreach ($this-\u003eerrors as $e) {","                print_r($e);","            }","            echo '\u003c/pre\u003e';","        }","    }","","    /**","     * Get an array of error messages, if any.","     *","     * @return array","     */","    public function getErrors()","    {","        return $this-\u003eerrors;","    }","","    /**","     * POP3 connection error handler.","     *","     * @param int    $errno","     * @param string $errstr","     * @param string $errfile","     * @param int    $errline","     */","    protected function catchWarning($errno, $errstr, $errfile, $errline)","    {","        $this-\u003esetError(","            'Connecting to the POP3 server raised a PHP warning:' .","            \"errno: $errno errstr: $errstr; errfile: $errfile; errline: $errline\"","        );","    }","}"],"stylingDirectives":null,"colorizedLines":["\u003cspan class=pl-ent\u003e\u0026lt;?php\u003c/span\u003e","","\u003cspan class=pl-c\u003e/**\u003c/span\u003e","\u003cspan class=pl-c\u003e * PHPMailer POP-Before-SMTP Authentication Class.\u003c/span\u003e","\u003cspan class=pl-c\u003e * PHP Version 5.5.\u003c/span\u003e","\u003cspan class=pl-c\u003e *\u003c/span\u003e","\u003cspan class=pl-c\u0